if psi_in:
    psi_out = existing.setdefault('psi', {})
    psi_ts = existing.setdefault('_psi_timestamps', {})
    for strategy in ('mobile', 'desktop'):
        if psi_in.get(strategy) and incoming.get('timestamp', '') >= psi_ts.get(strategy, ''):
